/**
 * Teachers Management Page
 * List, add, delete teachers
 */

import React, { useState, useEffect } from 'react';
import { getTeachers, createTeacher, deleteTeacher } from '../../services/admin_service';
import { getDepartments } from '../../services/admin_service';
import SearchBar from '../../components/common/SearchBar';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';

const Teachers = () => {
    const [teachers, setTeachers] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [filteredTeachers, setFilteredTeachers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showAddModal, setShowAddModal] = useState(false);
    const [showDeleteModal, setShowDeleteModal] = useState(false);
    const [selectedTeacher, setSelectedTeacher] = useState(null);
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        department_id: ''
    });
    const [error, setError] = useState('');

    useEffect(() => {
        fetchData();
    }, []);

    useEffect(() => {
        filterTeachers();
    }, [searchTerm, teachers]);

    const fetchData = async () => {
        setLoading(true);
        const [teachersRes, deptsRes] = await Promise.all([
            getTeachers(),
            getDepartments()
        ]);

        if (teachersRes.success) {
            setTeachers(teachersRes.data || []);
        }
        if (deptsRes.success) {
            setDepartments(deptsRes.data || []);
        }
        setLoading(false);
    };

    const filterTeachers = () => {
        if (!searchTerm) {
            setFilteredTeachers(teachers);
        } else {
            const filtered = teachers.filter(teacher =>
                teacher.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                teacher.email?.toLowerCase().includes(searchTerm.toLowerCase())
            );
            setFilteredTeachers(filtered);
        }
    };

    const handleAddTeacher = async () => {
        if (!formData.name || !formData.email || !formData.department_id) {
            setError('All fields are required');
            return;
        }

        const result = await createTeacher(formData);
        if (result.success) {
            setShowAddModal(false);
            setFormData({ name: '', email: '', department_id: '' });
            fetchData();
        } else {
            setError(result.message);
        }
    };

    const handleDeleteTeacher = async () => {
        if (!selectedTeacher) return;

        const result = await deleteTeacher(selectedTeacher.teacher_id);
        if (result.success) {
            setShowDeleteModal(false);
            setSelectedTeacher(null);
            fetchData();
        } else {
            setError(result.message);
        }
    };

    if (loading) return <LoadingSpinner />;

    return (
        <div className="page-container">
            <div className="page-header">
                <h1>Teachers</h1>
                <p>{teachers.length} faculty members</p>
            </div>

            <div className="page-actions">
                <SearchBar
                    placeholder="Search teachers by name or email..."
                    onSearch={setSearchTerm}
                />
                <button className="btn-primary" onClick={() => setShowAddModal(true)}>
                    + Add Teacher
                </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="data-table-container">
                <table className="data-table">
                    <thead>
                        <tr>
                            <th>ID</th>
                            <th>Name</th>
                            <th>Email</th>
                            <th>Department</th>
                            <th>Status</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredTeachers.map((teacher) => (
                            <tr key={teacher.teacher_id}>
                                <td>{teacher.teacher_id}</td>
                                <td><strong>{teacher.name}</strong></td>
                                <td>{teacher.email}</td>
                                <td>{teacher.Department?.name || 'N/A'}</td>
                                <td><StatusBadge status="Active" /></td>
                                <td>
                                    <button
                                        className="btn-icon btn-danger"
                                        onClick={() => {
                                            setSelectedTeacher(teacher);
                                            setShowDeleteModal(true);
                                        }}
                                    >
                                        🗑️
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Add Teacher Modal */}
            <ConfirmModal
                isOpen={showAddModal}
                onClose={() => setShowAddModal(false)}
                onConfirm={handleAddTeacher}
                title="Add Teacher"
                message={
                    <div className="modal-form">
                        <div className="form-group">
                            <label>Name:</label>
                            <input
                                type="text"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                placeholder="Dr. John Doe"
                            />
                        </div>
                        <div className="form-group">
                            <label>Email:</label>
                            <input
                                type="email"
                                value={formData.email}
                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                placeholder="john.doe@university.edu"
                            />
                        </div>
                        <div className="form-group">
                            <label>Department:</label>
                            <select
                                value={formData.department_id}
                                onChange={(e) => setFormData({ ...formData, department_id: e.target.value })}
                            >
                                <option value="">Select Department</option>
                                {departments.map(dept => (
                                    <option key={dept.department_id} value={dept.department_id}>
                                        {dept.name}
                                    </option>
                                ))}
                            </select>
                        </div>
                    </div>
                }
                confirmText="Add Teacher"
                confirmVariant="primary"
            />

            {/* Delete Modal */}
            <ConfirmModal
                isOpen={showDeleteModal}
                onClose={() => setShowDeleteModal(false)}
                onConfirm={handleDeleteTeacher}
                title="Delete Teacher"
                message={`Are you sure you want to delete "${selectedTeacher?.name}"? This action cannot be undone.`}
                confirmText="Delete"
                confirmVariant="danger"
            />
        </div>
    );
};

export default Teachers;
